"use client";

import type { Metadata } from "next";
import { rosaline, geistSans } from "./_fonts";
import "./globals.css";
import { SmoothCursor } from "@/components/ui/smooth-cursor";
import Navbar from "@/components/Navbar";
import { LenisWrapper } from "@/components/LenisWrapper";
import { useIsDesktop } from "@/hooks/use-outside-click";

export const metadata: Metadata = {
  title: "Create Next App",
  description: "Generated by create next app",
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const isDesktop = useIsDesktop(); // >= 768px

  return (
    <html lang="en">
      <body
        className={`${geistSans.variable} ${rosaline.variable} antialiased ${isDesktop ? "cursor-none" : "cursor-auto"
          }`}
      >
        <LenisWrapper>
          {isDesktop && <SmoothCursor />} {/* mobile pe nahi chalega */}
          <Navbar />
          {children}
        </LenisWrapper>
      </body>
    </html>
  );
}
